package com.payment.validation

import com.payment.model.CardType
import com.payment.model.CardValidationResult
import java.math.BigDecimal
import java.util.Calendar

class PaymentValidator {

    fun validateCardNumber(cardNumber: String): CardValidationResult {
        val cleaned = cardNumber.replace("\\s|-".toRegex(), "")
        val errors = mutableListOf<String>()

        if (cleaned.isEmpty()) {
            return CardValidationResult(false, null, listOf("Card number is required"))
        }

        if (!cleaned.all { it.isDigit() }) {
            errors.add("Card number must contain only digits")
        }

        val cardType = detectCardType(cleaned)

        val expectedLength = when (cardType) {
            CardType.AMEX -> 15
            else -> 16
        }

        if (cleaned.length != expectedLength) {
            errors.add("Invalid card number length for ${cardType?.name ?: "this card type"}")
        }

        if (!luhnCheck(cleaned)) {
            errors.add("Invalid card number")
        }

        return CardValidationResult(
            isValid = errors.isEmpty(),
            cardType = cardType,
            errors = errors
        )
    }

    fun validateExpiry(month: Int, year: Int): Pair<Boolean, String?> {
        if (month < 1 || month > 12) {
            return Pair(false, "Invalid expiry month")
        }

        val calendar = Calendar.getInstance()
        val currentYear = calendar.get(Calendar.YEAR)
        val currentMonth = calendar.get(Calendar.MONTH) + 1

        val fullYear = if (year < 100) year + 2000 else year

        if (fullYear < currentYear || (fullYear == currentYear && month < currentMonth)) {
            return Pair(false, "Card has expired")
        }

        if (fullYear > currentYear + 20) {
            return Pair(false, "Invalid expiry year")
        }

        return Pair(true, null)
    }

    fun validateCVV(cvv: String, cardType: CardType?): Pair<Boolean, String?> {
        if (cvv.isEmpty()) {
            return Pair(false, "CVV is required")
        }

        if (!cvv.all { it.isDigit() }) {
            return Pair(false, "CVV must contain only digits")
        }

        val expectedLength = if (cardType == CardType.AMEX) 4 else 3

        if (cvv.length != expectedLength) {
            return Pair(false, "CVV must be $expectedLength digits for ${cardType?.name ?: "this card type"}")
        }

        return Pair(true, null)
    }

    fun validateAmount(amount: BigDecimal, minAmount: BigDecimal = BigDecimal("0.01"), maxAmount: BigDecimal = BigDecimal("99999.99")): Pair<Boolean, String?> {
        if (amount <= BigDecimal.ZERO) {
            return Pair(false, "Amount must be greater than zero")
        }

        if (amount < minAmount) {
            return Pair(false, "Minimum amount is $minAmount")
        }

        if (amount > maxAmount) {
            return Pair(false, "Maximum amount is $maxAmount")
        }

        if (amount.scale() > 2) {
            return Pair(false, "Amount cannot have more than 2 decimal places")
        }

        return Pair(true, null)
    }

    fun validateEmail(email: String): Pair<Boolean, String?> {
        if (email.isEmpty()) {
            return Pair(false, "Email is required")
        }

        val emailRegex = "^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,}$".toRegex()
        if (!emailRegex.matches(email)) {
            return Pair(false, "Invalid email format")
        }

        return Pair(true, null)
    }

    private fun detectCardType(cardNumber: String): CardType {
        return when {
            cardNumber.startsWith("4") -> CardType.VISA
            cardNumber.take(2).toIntOrNull()?.let { it in 51..55 } == true -> CardType.MASTERCARD
            cardNumber.startsWith("2221") || cardNumber.startsWith("2720") -> CardType.MASTERCARD
            cardNumber.startsWith("34") || cardNumber.startsWith("37") -> CardType.AMEX
            cardNumber.startsWith("6011") || cardNumber.startsWith("65") -> CardType.DISCOVER
            else -> CardType.UNKNOWN
        }
    }

    private fun luhnCheck(cardNumber: String): Boolean {
        if (cardNumber.length < 2) return false

        var sum = 0
        var alternate = false

        for (i in cardNumber.length - 1 downTo 0) {
            var n = cardNumber[i].digitToInt()
            if (alternate) {
                n *= 2
                if (n > 9) n -= 9
            }
            sum += n
            alternate = !alternate
        }

        return sum % 10 == 0
    }
}

