package com.payment.billing

import android.app.Activity
import android.content.Context
import android.util.Log
import com.android.billingclient.api.*
import com.payment.model.*
import kotlinx.coroutines.*
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import java.math.BigDecimal

class InAppBillingManager(
    private val context: Context,
    private val verificationCallback: PurchaseVerificationCallback
) : PurchasesUpdatedListener {

    companion object {
        private const val TAG = "InAppBillingManager"
        private const val MAX_RETRY_COUNT = 3
        private const val RETRY_DELAY_MS = 1000L
    }

    interface PurchaseVerificationCallback {
        suspend fun verifyPurchase(purchase: Purchase): Boolean
        fun onPurchaseCompleted(transaction: Transaction)
        fun onPurchaseFailed(errorCode: PaymentErrorCode, message: String)
    }

    private var billingClient: BillingClient? = null
    private val scope = CoroutineScope(Dispatchers.Main + SupervisorJob())

    private val _connectionState = MutableStateFlow(false)
    val connectionState: StateFlow<Boolean> = _connectionState.asStateFlow()

    private val _availableProducts = MutableStateFlow<List<ProductDetails>>(emptyList())
    val availableProducts: StateFlow<List<ProductDetails>> = _availableProducts.asStateFlow()

    private val _purchaseHistory = MutableStateFlow<List<Transaction>>(emptyList())
    val purchaseHistory: StateFlow<List<Transaction>> = _purchaseHistory.asStateFlow()

    private var retryCount = 0

    fun initialize() {
        billingClient = BillingClient.newBuilder(context)
            .setListener(this)
            .enablePendingPurchases()
            .build()

        connectToBillingService()
    }

    private fun connectToBillingService() {
        billingClient?.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(billingResult: BillingResult) {
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    Log.d(TAG, "Billing service connected")
                    _connectionState.value = true
                    retryCount = 0
                    scope.launch {
                        queryExistingPurchases()
                    }
                } else {
                    Log.e(TAG, "Billing setup failed: ${billingResult.debugMessage}")
                    _connectionState.value = false
                }
            }

            override fun onBillingServiceDisconnected() {
                Log.w(TAG, "Billing service disconnected")
                _connectionState.value = false
                retryConnection()
            }
        })
    }

    private fun retryConnection() {
        if (retryCount < MAX_RETRY_COUNT) {
            retryCount++
            scope.launch {
                delay(RETRY_DELAY_MS * retryCount)
                connectToBillingService()
            }
        }
    }

    suspend fun queryProducts(
        productIds: List<String>,
        productType: String = BillingClient.ProductType.INAPP
    ): List<ProductDetails> {
        val client = billingClient ?: return emptyList()

        if (!_connectionState.value) {
            Log.w(TAG, "Billing client not connected")
            return emptyList()
        }

        val productList = productIds.map { productId ->
            QueryProductDetailsParams.Product.newBuilder()
                .setProductId(productId)
                .setProductType(productType)
                .build()
        }

        val params = QueryProductDetailsParams.newBuilder()
            .setProductList(productList)
            .build()

        return suspendCancellableCoroutine { continuation ->
            client.queryProductDetailsAsync(params) { billingResult, productDetailsList ->
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    _availableProducts.value = productDetailsList
                    continuation.resume(productDetailsList) {}
                } else {
                    Log.e(TAG, "Query products failed: ${billingResult.debugMessage}")
                    continuation.resume(emptyList()) {}
                }
            }
        }
    }

    fun launchPurchaseFlow(activity: Activity, productDetails: ProductDetails): BillingResult? {
        val client = billingClient ?: return null

        val offerToken = productDetails.subscriptionOfferDetails?.firstOrNull()?.offerToken

        val productDetailsParamsBuilder = BillingFlowParams.ProductDetailsParams.newBuilder()
            .setProductDetails(productDetails)

        if (offerToken != null) {
            productDetailsParamsBuilder.setOfferToken(offerToken)
        }

        val billingFlowParams = BillingFlowParams.newBuilder()
            .setProductDetailsParamsList(listOf(productDetailsParamsBuilder.build()))
            .build()

        return client.launchBillingFlow(activity, billingFlowParams)
    }

    override fun onPurchasesUpdated(billingResult: BillingResult, purchases: MutableList<Purchase>?) {
        when (billingResult.responseCode) {
            BillingClient.BillingResponseCode.OK -> {
                purchases?.forEach { purchase ->
                    scope.launch {
                        handlePurchase(purchase)
                    }
                }
            }
            BillingClient.BillingResponseCode.USER_CANCELED -> {
                verificationCallback.onPurchaseFailed(
                    PaymentErrorCode.USER_CANCELLED,
                    "Purchase cancelled by user"
                )
            }
            BillingClient.BillingResponseCode.ITEM_ALREADY_OWNED -> {
                verificationCallback.onPurchaseFailed(
                    PaymentErrorCode.ITEM_ALREADY_OWNED,
                    "Item already owned"
                )
            }
            else -> {
                verificationCallback.onPurchaseFailed(
                    PaymentErrorCode.UNKNOWN_ERROR,
                    "Purchase failed: ${billingResult.debugMessage}"
                )
            }
        }
    }

    private suspend fun handlePurchase(purchase: Purchase) {
        if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED) {
            val isVerified = verificationCallback.verifyPurchase(purchase)

            if (isVerified) {
                if (!purchase.isAcknowledged) {
                    acknowledgePurchase(purchase)
                }

                val transaction = Transaction(
                    type = TransactionType.IN_APP_PURCHASE,
                    amount = BigDecimal.ZERO,
                    currency = Currency.USD,
                    status = PaymentStatus.COMPLETED,
                    description = "In-app purchase: ${purchase.products.joinToString()}",
                    receiptToken = purchase.purchaseToken,
                    metadata = mapOf(
                        "orderId" to (purchase.orderId ?: ""),
                        "products" to purchase.products.joinToString(",")
                    )
                )

                verificationCallback.onPurchaseCompleted(transaction)
            } else {
                verificationCallback.onPurchaseFailed(
                    PaymentErrorCode.VERIFICATION_FAILED,
                    "Purchase verification failed"
                )
            }
        } else if (purchase.purchaseState == Purchase.PurchaseState.PENDING) {
            Log.d(TAG, "Purchase is pending")
        }
    }

    private suspend fun acknowledgePurchase(purchase: Purchase) {
        val client = billingClient ?: return

        val acknowledgeParams = AcknowledgePurchaseParams.newBuilder()
            .setPurchaseToken(purchase.purchaseToken)
            .build()

        suspendCancellableCoroutine<Unit> { continuation ->
            client.acknowledgePurchase(acknowledgeParams) { billingResult ->
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    Log.d(TAG, "Purchase acknowledged")
                } else {
                    Log.e(TAG, "Acknowledge failed: ${billingResult.debugMessage}")
                }
                continuation.resume(Unit) {}
            }
        }
    }

    suspend fun consumePurchase(purchase: Purchase): Boolean {
        val client = billingClient ?: return false

        val consumeParams = ConsumeParams.newBuilder()
            .setPurchaseToken(purchase.purchaseToken)
            .build()

        return suspendCancellableCoroutine { continuation ->
            client.consumeAsync(consumeParams) { billingResult, _ ->
                continuation.resume(billingResult.responseCode == BillingClient.BillingResponseCode.OK) {}
            }
        }
    }

    private suspend fun queryExistingPurchases() {
        val client = billingClient ?: return

        val params = QueryPurchasesParams.newBuilder()
            .setProductType(BillingClient.ProductType.INAPP)
            .build()

        client.queryPurchasesAsync(params) { billingResult, purchases ->
            if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                purchases.forEach { purchase ->
                    if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED && !purchase.isAcknowledged) {
                        scope.launch {
                            handlePurchase(purchase)
                        }
                    }
                }
            }
        }
    }

    fun destroy() {
        scope.cancel()
        billingClient?.endConnection()
        billingClient = null
    }
}

