package com.payment.wallet

import com.payment.model.*
import com.payment.security.SecureDataManager
import com.google.gson.Gson
import com.google.gson.reflect.TypeToken
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.sync.Mutex
import kotlinx.coroutines.sync.withLock
import java.math.BigDecimal
import java.util.UUID

class WalletManager(
    private val secureDataManager: SecureDataManager,
    private val userId: String
) {

    companion object {
        private const val WALLET_KEY_PREFIX = "wallet_"
        private const val TRANSACTIONS_KEY_PREFIX = "wallet_txns_"
        private const val PAYMENT_METHODS_KEY = "payment_methods_"
        private const val MAX_TRANSACTION_AMOUNT = 10000.0
        private const val MIN_TRANSACTION_AMOUNT = 0.01
        private const val MAX_DAILY_TRANSACTIONS = 50
    }

    private val gson = Gson()
    private val mutex = Mutex()

    private val _walletInfo = MutableStateFlow<WalletInfo?>(null)
    val walletInfo: StateFlow<WalletInfo?> = _walletInfo.asStateFlow()

    private val _transactions = MutableStateFlow<List<Transaction>>(emptyList())
    val transactions: StateFlow<List<Transaction>> = _transactions.asStateFlow()

    private val _paymentMethods = MutableStateFlow<List<PaymentMethod>>(emptyList())
    val paymentMethods: StateFlow<List<PaymentMethod>> = _paymentMethods.asStateFlow()

    fun initialize() {
        loadWalletInfo()
        loadTransactions()
        loadPaymentMethods()
    }

    suspend fun topUpWallet(
        amount: BigDecimal,
        currency: Currency,
        paymentMethodId: String
    ): PaymentResult = mutex.withLock {
        val amountValidation = validateAmount(amount)
        if (!amountValidation.first) {
            return PaymentResult(
                success = false,
                errorCode = PaymentErrorCode.AMOUNT_EXCEEDS_LIMIT,
                errorMessage = amountValidation.second
            )
        }

        val paymentMethod = _paymentMethods.value.find { it.id == paymentMethodId }
            ?: return PaymentResult(
                success = false,
                errorCode = PaymentErrorCode.INVALID_PAYMENT_METHOD,
                errorMessage = "Payment method not found"
            )

        val wallet = _walletInfo.value ?: createWallet(currency)

        if (wallet.isLocked) {
            return PaymentResult(
                success = false,
                errorCode = PaymentErrorCode.WALLET_LOCKED,
                errorMessage = "Wallet is locked"
            )
        }

        if (!checkDailyTransactionLimit()) {
            return PaymentResult(
                success = false,
                errorCode = PaymentErrorCode.AMOUNT_EXCEEDS_LIMIT,
                errorMessage = "Daily transaction limit exceeded"
            )
        }

        val transaction = Transaction(
            type = TransactionType.WALLET_TOP_UP,
            amount = amount,
            currency = currency,
            status = PaymentStatus.PROCESSING,
            description = "Wallet top-up via ${paymentMethod.type.name}",
            paymentMethodId = paymentMethodId,
            metadata = mapOf("walletId" to userId)
        )

        return try {
            val updatedWallet = wallet.copy(
                balance = wallet.balance + amount,
                lastUpdated = System.currentTimeMillis()
            )

            val completedTransaction = transaction.copy(status = PaymentStatus.COMPLETED)

            saveWalletInfo(updatedWallet)
            addTransaction(completedTransaction)

            PaymentResult(
                success = true,
                transaction = completedTransaction
            )
        } catch (e: Exception) {
            val failedTransaction = transaction.copy(
                status = PaymentStatus.FAILED,
                errorMessage = e.message
            )
            addTransaction(failedTransaction)

            PaymentResult(
                success = false,
                transaction = failedTransaction,
                errorCode = PaymentErrorCode.UNKNOWN_ERROR,
                errorMessage = "Top-up failed: ${e.message}"
            )
        }
    }

    suspend fun withdrawFromWallet(
        amount: BigDecimal,
        currency: Currency
    ): PaymentResult = mutex.withLock {
        val amountValidation = validateAmount(amount)
        if (!amountValidation.first) {
            return PaymentResult(
                success = false,
                errorCode = PaymentErrorCode.AMOUNT_EXCEEDS_LIMIT,
                errorMessage = amountValidation.second
            )
        }

        val wallet = _walletInfo.value ?: return PaymentResult(
            success = false,
            errorCode = PaymentErrorCode.INSUFFICIENT_FUNDS,
            errorMessage = "Wallet not found"
        )

        if (wallet.isLocked) {
            return PaymentResult(
                success = false,
                errorCode = PaymentErrorCode.WALLET_LOCKED,
                errorMessage = "Wallet is locked"
            )
        }

        if (wallet.balance < amount) {
            return PaymentResult(
                success = false,
                errorCode = PaymentErrorCode.INSUFFICIENT_FUNDS,
                errorMessage = "Insufficient wallet balance"
            )
        }

        val transaction = Transaction(
            type = TransactionType.WALLET_WITHDRAWAL,
            amount = amount,
            currency = currency,
            status = PaymentStatus.PROCESSING,
            description = "Wallet withdrawal"
        )

        return try {
            val updatedWallet = wallet.copy(
                balance = wallet.balance - amount,
                lastUpdated = System.currentTimeMillis()
            )

            val completedTransaction = transaction.copy(status = PaymentStatus.COMPLETED)

            saveWalletInfo(updatedWallet)
            addTransaction(completedTransaction)

            PaymentResult(
                success = true,
                transaction = completedTransaction
            )
        } catch (e: Exception) {
            val failedTransaction = transaction.copy(
                status = PaymentStatus.FAILED,
                errorMessage = e.message
            )
            addTransaction(failedTransaction)

            PaymentResult(
                success = false,
                transaction = failedTransaction,
                errorCode = PaymentErrorCode.UNKNOWN_ERROR,
                errorMessage = "Withdrawal failed: ${e.message}"
            )
        }
    }

    suspend fun makePayment(
        amount: BigDecimal,
        currency: Currency,
        description: String
    ): PaymentResult = mutex.withLock {
        val wallet = _walletInfo.value ?: return PaymentResult(
            success = false,
            errorCode = PaymentErrorCode.INSUFFICIENT_FUNDS,
            errorMessage = "Wallet not initialized"
        )

        if (wallet.isLocked) {
            return PaymentResult(
                success = false,
                errorCode = PaymentErrorCode.WALLET_LOCKED,
                errorMessage = "Wallet is locked"
            )
        }

        if (wallet.balance < amount) {
            return PaymentResult(
                success = false,
                errorCode = PaymentErrorCode.INSUFFICIENT_FUNDS,
                errorMessage = "Insufficient balance. Available: ${wallet.balance}"
            )
        }

        val transaction = Transaction(
            type = TransactionType.IN_APP_PURCHASE,
            amount = amount,
            currency = currency,
            status = PaymentStatus.PROCESSING,
            description = description
        )

        return try {
            val updatedWallet = wallet.copy(
                balance = wallet.balance - amount,
                lastUpdated = System.currentTimeMillis()
            )

            val completedTransaction = transaction.copy(status = PaymentStatus.COMPLETED)

            saveWalletInfo(updatedWallet)
            addTransaction(completedTransaction)

            PaymentResult(
                success = true,
                transaction = completedTransaction
            )
        } catch (e: Exception) {
            val failedTransaction = transaction.copy(
                status = PaymentStatus.FAILED,
                errorMessage = e.message
            )
            addTransaction(failedTransaction)

            PaymentResult(
                success = false,
                transaction = failedTransaction,
                errorCode = PaymentErrorCode.UNKNOWN_ERROR,
                errorMessage = "Payment failed: ${e.message}"
            )
        }
    }

    suspend fun addPaymentMethod(paymentMethod: PaymentMethod): Boolean = mutex.withLock {
        return try {
            val encryptedToken = paymentMethod.encryptedToken?.let {
                secureDataManager.encryptData(it)
            }

            val secureMethod = paymentMethod.copy(
                encryptedToken = encryptedToken?.cipherText
            )

            val methods = _paymentMethods.value.toMutableList()
            if (secureMethod.isDefault) {
                methods.replaceAll { it.copy(isDefault = false) }
            }
            methods.add(secureMethod)

            savePaymentMethods(methods)
            true
        } catch (e: Exception) {
            false
        }
    }

    suspend fun removePaymentMethod(paymentMethodId: String): Boolean = mutex.withLock {
        val methods = _paymentMethods.value.toMutableList()
        val removed = methods.removeAll { it.id == paymentMethodId }
        if (removed) {
            savePaymentMethods(methods)
        }
        return removed
    }

    fun getBalance(): BigDecimal {
        return _walletInfo.value?.balance ?: BigDecimal.ZERO
    }

    fun getTransactionHistory(
        limit: Int = 50,
        offset: Int = 0,
        type: TransactionType? = null
    ): List<Transaction> {
        var filtered = _transactions.value
        if (type != null) {
            filtered = filtered.filter { it.type == type }
        }
        return filtered
            .sortedByDescending { it.timestamp }
            .drop(offset)
            .take(limit)
    }

    private fun createWallet(currency: Currency): WalletInfo {
        val wallet = WalletInfo(
            userId = userId,
            balance = BigDecimal.ZERO,
            currency = currency
        )
        saveWalletInfo(wallet)
        return wallet
    }

    private fun saveWalletInfo(walletInfo: WalletInfo) {
        val json = gson.toJson(walletInfo)
        secureDataManager.storeSecureData("${WALLET_KEY_PREFIX}$userId", json)
        _walletInfo.value = walletInfo
    }

    private fun loadWalletInfo() {
        val json = secureDataManager.getSecureData("${WALLET_KEY_PREFIX}$userId")
        if (json != null) {
            _walletInfo.value = gson.fromJson(json, WalletInfo::class.java)
        }
    }

    private fun addTransaction(transaction: Transaction) {
        val current = _transactions.value.toMutableList()
        current.add(transaction)
        saveTransactions(current)
    }

    private fun saveTransactions(transactions: List<Transaction>) {
        val json = gson.toJson(transactions)
        val encrypted = secureDataManager.encryptData(json)
        secureDataManager.storeSecureData(
            "${TRANSACTIONS_KEY_PREFIX}$userId",
            gson.toJson(encrypted)
        )
        _transactions.value = transactions
    }

    private fun loadTransactions() {
        try {
            val encryptedJson = secureDataManager.getSecureData("${TRANSACTIONS_KEY_PREFIX}$userId")
            if (encryptedJson != null) {
                val encryptedData = gson.fromJson(
                    encryptedJson,
                    SecureDataManager.EncryptedData::class.java
                )
                val decrypted = secureDataManager.decryptData(encryptedData)
                val type = object : TypeToken<List<Transaction>>() {}.type
                _transactions.value = gson.fromJson(decrypted, type)
            }
        } catch (e: Exception) {
            _transactions.value = emptyList()
        }
    }

    private fun savePaymentMethods(methods: List<PaymentMethod>) {
        val json = gson.toJson(methods)
        val encrypted = secureDataManager.encryptData(json)
        secureDataManager.storeSecureData(
            "${PAYMENT_METHODS_KEY}$userId",
            gson.toJson(encrypted)
        )
        _paymentMethods.value = methods
    }

    private fun loadPaymentMethods() {
        try {
            val encryptedJson = secureDataManager.getSecureData("${PAYMENT_METHODS_KEY}$userId")
            if (encryptedJson != null) {
                val encryptedData = gson.fromJson(
                    encryptedJson,
                    SecureDataManager.EncryptedData::class.java
                )
                val decrypted = secureDataManager.decryptData(encryptedData)
                val type = object : TypeToken<List<PaymentMethod>>() {}.type
                _paymentMethods.value = gson.fromJson(decrypted, type)
            }
        } catch (e: Exception) {
            _paymentMethods.value = emptyList()
        }
    }

    private fun validateAmount(amount: BigDecimal): Pair<Boolean, String?> {
        if (amount <= BigDecimal.ZERO) {
            return Pair(false, "Amount must be positive")
        }
        if (amount > BigDecimal(MAX_TRANSACTION_AMOUNT)) {
            return Pair(false, "Amount exceeds maximum limit of $MAX_TRANSACTION_AMOUNT")
        }
        if (amount < BigDecimal(MIN_TRANSACTION_AMOUNT)) {
            return Pair(false, "Amount below minimum of $MIN_TRANSACTION_AMOUNT")
        }
        return Pair(true, null)
    }

    private fun checkDailyTransactionLimit(): Boolean {
        val oneDayAgo = System.currentTimeMillis() - (24 * 60 * 60 * 1000)
        val todayTransactions = _transactions.value.count { it.timestamp > oneDayAgo }
        return todayTransactions < MAX_DAILY_TRANSACTIONS
    }

    fun destroy() {
        // Clear sensitive data from memory
    }
}

