package com.payment.network

import android.util.Log
import com.payment.model.PaymentErrorCode
import com.payment.model.PaymentResult
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import java.io.BufferedReader
import java.io.InputStreamReader
import java.io.OutputStreamWriter
import java.net.HttpURLConnection
import java.net.URL
import java.security.cert.X509Certificate
import javax.net.ssl.HttpsURLConnection
import javax.net.ssl.SSLContext
import javax.net.ssl.TrustManager
import javax.net.ssl.X509TrustManager

class SecureNetworkClient(
    private val baseUrl: String,
    private val apiKey: String
) {

    companion object {
        private const val TAG = "SecureNetworkClient"
        private const val CONNECT_TIMEOUT = 15000
        private const val READ_TIMEOUT = 30000
    }

    data class NetworkResponse(
        val code: Int,
        val body: String?,
        val isSuccessful: Boolean
    )

    suspend fun post(
        endpoint: String,
        body: String,
        additionalHeaders: Map<String, String> = emptyMap()
    ): NetworkResponse = withContext(Dispatchers.IO) {
        var connection: HttpURLConnection? = null
        try {
            val url = URL("$baseUrl$endpoint")
            connection = (url.openConnection() as HttpsURLConnection).apply {
                requestMethod = "POST"
                connectTimeout = CONNECT_TIMEOUT
                readTimeout = READ_TIMEOUT
                doOutput = true
                doInput = true

                setRequestProperty("Content-Type", "application/json")
                setRequestProperty("Authorization", "Bearer $apiKey")
                setRequestProperty("X-Request-Id", java.util.UUID.randomUUID().toString())

                additionalHeaders.forEach { (key, value) ->
                    setRequestProperty(key, value)
                }
            }

            OutputStreamWriter(connection.outputStream).use { writer ->
                writer.write(body)
                writer.flush()
            }

            val responseCode = connection.responseCode
            val responseBody = if (responseCode in 200..299) {
                BufferedReader(InputStreamReader(connection.inputStream)).use { it.readText() }
            } else {
                BufferedReader(InputStreamReader(connection.errorStream)).use { it.readText() }
            }

            NetworkResponse(
                code = responseCode,
                body = responseBody,
                isSuccessful = responseCode in 200..299
            )
        } catch (e: Exception) {
            Log.e(TAG, "Network request failed", e)
            NetworkResponse(
                code = -1,
                body = e.message,
                isSuccessful = false
            )
        } finally {
            connection?.disconnect()
        }
    }

    suspend fun get(
        endpoint: String,
        queryParams: Map<String, String> = emptyMap(),
        additionalHeaders: Map<String, String> = emptyMap()
    ): NetworkResponse = withContext(Dispatchers.IO) {
        var connection: HttpURLConnection? = null
        try {
            val queryString = if (queryParams.isNotEmpty()) {
                "?" + queryParams.entries.joinToString("&") { "${it.key}=${it.value}" }
            } else ""

            val url = URL("$baseUrl$endpoint$queryString")
            connection = (url.openConnection() as HttpsURLConnection).apply {
                requestMethod = "GET"
                connectTimeout = CONNECT_TIMEOUT
                readTimeout = READ_TIMEOUT

                setRequestProperty("Authorization", "Bearer $apiKey")
                setRequestProperty("X-Request-Id", java.util.UUID.randomUUID().toString())

                additionalHeaders.forEach { (key, value) ->
                    setRequestProperty(key, value)
                }
            }

            val responseCode = connection.responseCode
            val responseBody = if (responseCode in 200..299) {
                BufferedReader(InputStreamReader(connection.inputStream)).use { it.readText() }
            } else {
                BufferedReader(InputStreamReader(connection.errorStream)).use { it.readText() }
            }

            NetworkResponse(
                code = responseCode,
                body = responseBody,
                isSuccessful = responseCode in 200..299
            )
        } catch (e: Exception) {
            Log.e(TAG, "Network request failed", e)
            NetworkResponse(
                code = -1,
                body = e.message,
                isSuccessful = false
            )
        } finally {
            connection?.disconnect()
        }
    }
}

