package com.payment.fraud

import android.content.Context
import android.os.Build
import android.provider.Settings
import com.payment.model.Transaction
import java.math.BigDecimal
import java.util.concurrent.ConcurrentLinkedQueue

class FraudDetector(private val context: Context) {

    companion object {
        private const val MAX_TRANSACTIONS_PER_MINUTE = 5
        private const val MAX_AMOUNT_PER_TRANSACTION = 5000.0
        private const val MAX_DAILY_AMOUNT = 25000.0
        private const val SUSPICIOUS_RAPID_INTERVAL_MS = 5000L
    }

    data class RiskAssessment(
        val riskLevel: RiskLevel,
        val riskScore: Int,
        val flags: List<String>,
        val shouldBlock: Boolean
    )

    enum class RiskLevel {
        LOW,
        MEDIUM,
        HIGH,
        CRITICAL
    }

    private val recentTransactions = ConcurrentLinkedQueue<TransactionRecord>()

    private data class TransactionRecord(
        val amount: BigDecimal,
        val timestamp: Long
    )

    fun assessRisk(transaction: Transaction): RiskAssessment {
        val flags = mutableListOf<String>()
        var riskScore = 0

        // Check device integrity
        if (isDeviceRooted()) {
            flags.add("ROOTED_DEVICE")
            riskScore += 30
        }

        if (isEmulator()) {
            flags.add("EMULATOR_DETECTED")
            riskScore += 20
        }

        if (isDeveloperModeEnabled()) {
            flags.add("DEVELOPER_MODE")
            riskScore += 10
        }

        // Check transaction patterns
        if (transaction.amount > BigDecimal(MAX_AMOUNT_PER_TRANSACTION)) {
            flags.add("HIGH_AMOUNT")
            riskScore += 25
        }

        val now = System.currentTimeMillis()
        val oneMinuteAgo = now - 60_000
        val recentCount = recentTransactions.count { it.timestamp > oneMinuteAgo }
        if (recentCount >= MAX_TRANSACTIONS_PER_MINUTE) {
            flags.add("RAPID_TRANSACTIONS")
            riskScore += 35
        }

        // Check for rapid successive transactions
        val lastTransaction = recentTransactions.lastOrNull()
        if (lastTransaction != null && (now - lastTransaction.timestamp) < SUSPICIOUS_RAPID_INTERVAL_MS) {
            flags.add("SUSPICIOUS_TIMING")
            riskScore += 15
        }

        // Check daily total
        val oneDayAgo = now - (24 * 60 * 60 * 1000)
        val dailyTotal = recentTransactions
            .filter { it.timestamp > oneDayAgo }
            .fold(BigDecimal.ZERO) { acc, record -> acc + record.amount }

        if (dailyTotal + transaction.amount > BigDecimal(MAX_DAILY_AMOUNT)) {
            flags.add("DAILY_LIMIT_EXCEEDED")
            riskScore += 30
        }

        // Record this transaction
        recentTransactions.add(TransactionRecord(transaction.amount, now))
        cleanOldRecords()

        val riskLevel = when {
            riskScore >= 80 -> RiskLevel.CRITICAL
            riskScore >= 50 -> RiskLevel.HIGH
            riskScore >= 25 -> RiskLevel.MEDIUM
            else -> RiskLevel.LOW
        }

        return RiskAssessment(
            riskLevel = riskLevel,
            riskScore = riskScore,
            flags = flags,
            shouldBlock = riskLevel == RiskLevel.CRITICAL
        )
    }

    private fun isDeviceRooted(): Boolean {
        val paths = arrayOf(
            "/system/app/Superuser.apk",
            "/sbin/su",
            "/system/bin/su",
            "/system/xbin/su",
            "/data/local/xbin/su",
            "/data/local/bin/su",
            "/system/sd/xbin/su",
            "/system/bin/failsafe/su",
            "/data/local/su"
        )

        return paths.any { java.io.File(it).exists() } ||
                try {
                    Runtime.getRuntime().exec("su")
                    true
                } catch (e: Exception) {
                    false
                }
    }

    private fun isEmulator(): Boolean {
        return (Build.FINGERPRINT.startsWith("generic")
                || Build.FINGERPRINT.startsWith("unknown")
                || Build.MODEL.contains("google_sdk")
                || Build.MODEL.contains("Emulator")
                || Build.MODEL.contains("Android SDK built for x86")
                || Build.MANUFACTURER.contains("Genymotion")
                || Build.BRAND.startsWith("generic") && Build.DEVICE.startsWith("generic")
                || "google_sdk" == Build.PRODUCT
                || Build.HARDWARE.contains("goldfish")
                || Build.HARDWARE.contains("ranchu"))
    }

    private fun isDeveloperModeEnabled(): Boolean {
        return try {
            Settings.Secure.getInt(
                context.contentResolver,
                Settings.Global.DEVELOPMENT_SETTINGS_ENABLED,
                0
            ) != 0
        } catch (e: Exception) {
            false
        }
    }

    private fun cleanOldRecords() {
        val oneDayAgo = System.currentTimeMillis() - (24 * 60 * 60 * 1000)
        recentTransactions.removeAll { it.timestamp < oneDayAgo }
    }
}

