package com.payment

import android.app.Activity
import android.content.Context
import android.util.Log
import com.android.billingclient.api.ProductDetails
import com.android.billingclient.api.Purchase
import com.payment.billing.InAppBillingManager
import com.payment.fraud.FraudDetector
import com.payment.model.*
import com.payment.network.SecureNetworkClient
import com.payment.security.SecureDataManager
import com.payment.validation.PaymentValidator
import com.payment.wallet.WalletManager
import com.google.gson.Gson
import kotlinx.coroutines.*
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import java.math.BigDecimal

class PaymentProcessor private constructor(
    private val context: Context,
    private val config: PaymentConfig
) {

    companion object {
        private const val TAG = "PaymentProcessor"

        @Volatile
        private var instance: PaymentProcessor? = null

        fun initialize(context: Context, config: PaymentConfig): PaymentProcessor {
            return instance ?: synchronized(this) {
                instance ?: PaymentProcessor(context.applicationContext, config).also {
                    instance = it
                }
            }
        }

        fun getInstance(): PaymentProcessor {
            return instance ?: throw IllegalStateException(
                "PaymentProcessor not initialized. Call initialize() first."
            )
        }
    }

    data class PaymentConfig(
        val apiBaseUrl: String,
        val apiKey: String,
        val userId: String,
        val enableFraudDetection: Boolean = true,
        val enableLogging: Boolean = false,
        val defaultCurrency: Currency = Currency.USD
    )

    interface PaymentEventListener {
        fun onPaymentStarted(transactionId: String)
        fun onPaymentCompleted(result: PaymentResult)
        fun onPaymentFailed(result: PaymentResult)
        fun onWalletUpdated(walletInfo: WalletInfo)
    }

    private val secureDataManager = SecureDataManager(context)
    private val validator = PaymentValidator()
    private val fraudDetector = FraudDetector(context)
    private val networkClient = SecureNetworkClient(config.apiBaseUrl, config.apiKey)
    private val gson = Gson()
    private val scope = CoroutineScope(Dispatchers.Main + SupervisorJob())

    private var eventListener: PaymentEventListener? = null

    val walletManager: WalletManager = WalletManager(secureDataManager, config.userId)

    private val billingManager: InAppBillingManager = InAppBillingManager(
        context,
        object : InAppBillingManager.PurchaseVerificationCallback {
            override suspend fun verifyPurchase(purchase: Purchase): Boolean {
                return verifyPurchaseWithServer(purchase)
            }

            override fun onPurchaseCompleted(transaction: Transaction) {
                _lastPaymentResult.value = PaymentResult(success = true, transaction = transaction)
                eventListener?.onPaymentCompleted(
                    PaymentResult(success = true, transaction = transaction)
                )
            }

            override fun onPurchaseFailed(errorCode: PaymentErrorCode, message: String) {
                val result = PaymentResult(
                    success = false,
                    errorCode = errorCode,
                    errorMessage = message
                )
                _lastPaymentResult.value = result
                eventListener?.onPaymentFailed(result)
            }
        }
    )

    private val _lastPaymentResult = MutableStateFlow<PaymentResult?>(null)
    val lastPaymentResult: StateFlow<PaymentResult?> = _lastPaymentResult.asStateFlow()

    private val _isProcessing = MutableStateFlow(false)
    val isProcessing: StateFlow<Boolean> = _isProcessing.asStateFlow()

    fun init() {
        billingManager.initialize()
        walletManager.initialize()
        log("PaymentProcessor initialized")
    }

    fun setEventListener(listener: PaymentEventListener) {
        this.eventListener = listener
    }

    // === In-App Purchase Methods ===

    suspend fun queryAvailableProducts(
        productIds: List<String>,
        productType: String = "inapp"
    ): List<ProductDetails> {
        return billingManager.queryProducts(productIds, productType)
    }

    fun launchPurchase(activity: Activity, productDetails: ProductDetails) {
        if (_isProcessing.value) {
            eventListener?.onPaymentFailed(
                PaymentResult(
                    success = false,
                    errorCode = PaymentErrorCode.UNKNOWN_ERROR,
                    errorMessage = "Another payment is already in progress"
                )
            )
            return
        }

        _isProcessing.value = true
        eventListener?.onPaymentStarted("iap_${productDetails.productId}")
        billingManager.launchPurchaseFlow(activity, productDetails)
        _isProcessing.value = false
    }

    // === Wallet Methods ===

    suspend fun topUpWallet(
        amount: BigDecimal,
        paymentMethodId: String
    ): PaymentResult {
        if (_isProcessing.value) {
            return PaymentResult(
                success = false,
                errorCode = PaymentErrorCode.UNKNOWN_ERROR,
                errorMessage = "Another payment is already in progress"
            )
        }

        _isProcessing.value = true

        try {
            val tempTransaction = Transaction(
                type = TransactionType.WALLET_TOP_UP,
                amount = amount,
                currency = config.defaultCurrency,
                description = "Wallet top-up"
            )

            if (config.enableFraudDetection) {
                val riskAssessment = fraudDetector.assessRisk(tempTransaction)
                if (riskAssessment.shouldBlock) {
                    val result = PaymentResult(
                        success = false,
                        errorCode = PaymentErrorCode.VERIFICATION_FAILED,
                        errorMessage = "Transaction blocked by fraud detection: ${riskAssessment.flags.joinToString()}"
                    )
                    eventListener?.onPaymentFailed(result)
                    return result
                }
                log("Risk assessment: ${riskAssessment.riskLevel} (score: ${riskAssessment.riskScore})")
            }

            eventListener?.onPaymentStarted(tempTransaction.id)

            val result = walletManager.topUpWallet(amount, config.defaultCurrency, paymentMethodId)

            if (result.success) {
                walletManager.walletInfo.value?.let { wallet ->
                    eventListener?.onWalletUpdated(wallet)
                }
                eventListener?.onPaymentCompleted(result)

                scope.launch {
                    reportTransactionToServer(result.transaction!!)
                }
            } else {
                eventListener?.onPaymentFailed(result)
            }

            _lastPaymentResult.value = result
            return result
        } finally {
            _isProcessing.value = false
        }
    }

    suspend fun makeWalletPayment(
        amount: BigDecimal,
        description: String
    ): PaymentResult {
        if (_isProcessing.value) {
            return PaymentResult(
                success = false,
                errorCode = PaymentErrorCode.UNKNOWN_ERROR,
                errorMessage = "Another payment is already in progress"
            )
        }

        _isProcessing.value = true

        try {
            val tempTransaction = Transaction(
                type = TransactionType.IN_APP_PURCHASE,
                amount = amount,
                currency = config.defaultCurrency,
                description = description
            )

            if (config.enableFraudDetection) {
                val riskAssessment = fraudDetector.assessRisk(tempTransaction)
                if (riskAssessment.shouldBlock) {
                    val result = PaymentResult(
                        success = false,
                        errorCode = PaymentErrorCode.VERIFICATION_FAILED,
                        errorMessage = "Transaction blocked: ${riskAssessment.flags.joinToString()}"
                    )
                    eventListener?.onPaymentFailed(result)
                    return result
                }
            }

            eventListener?.onPaymentStarted(tempTransaction.id)

            val result = walletManager.makePayment(amount, config.defaultCurrency, description)

            if (result.success) {
                walletManager.walletInfo.value?.let { wallet ->
                    eventListener?.onWalletUpdated(wallet)
                }
                eventListener?.onPaymentCompleted(result)

                scope.launch {
                    reportTransactionToServer(result.transaction!!)
                }
            } else {
                eventListener?.onPaymentFailed(result)
            }

            _lastPaymentResult.value = result
            return result
        } finally {
            _isProcessing.value = false
        }
    }

    suspend fun withdrawFromWallet(amount: BigDecimal): PaymentResult {
        if (_isProcessing.value) {
            return PaymentResult(
                success = false,
                errorCode = PaymentErrorCode.UNKNOWN_ERROR,
                errorMessage = "Another payment is already in progress"
            )
        }

        _isProcessing.value = true

        try {
            val result = walletManager.withdrawFromWallet(amount, config.defaultCurrency)

            if (result.success) {
                walletManager.walletInfo.value?.let { wallet ->
                    eventListener?.onWalletUpdated(wallet)
                }
                scope.launch {
                    reportTransactionToServer(result.transaction!!)
                }
            }

            _lastPaymentResult.value = result
            return result
        } finally {
            _isProcessing.value = false
        }
    }

    // === Payment Method Management ===

    suspend fun addCreditCard(
        cardNumber: String,
        expiryMonth: Int,
        expiryYear: Int,
        cvv: String,
        setAsDefault: Boolean = false
    ): Boolean {
        val cardValidation = validator.validateCardNumber(cardNumber)
        if (!cardValidation.isValid) {
            log("Card validation failed: ${cardValidation.errors}")
            return false
        }

        val expiryValidation = validator.validateExpiry(expiryMonth, expiryYear)
        if (!expiryValidation.first) {
            log("Expiry validation failed: ${expiryValidation.second}")
            return false
        }

        val cvvValidation = validator.validateCVV(cvv, cardValidation.cardType)
        if (!cvvValidation.first) {
            log("CVV validation failed: ${cvvValidation.second}")
            return false
        }

        val tokenData = "${cardNumber}_${expiryMonth}_${expiryYear}"
        val cleaned = cardNumber.replace("\\s".toRegex(), "")

        val paymentMethod = PaymentMethod(
            type = when (cardValidation.cardType) {
                CardType.VISA, CardType.MASTERCARD, CardType.AMEX, CardType.DISCOVER -> PaymentMethodType.CREDIT_CARD
                else -> PaymentMethodType.CREDIT_CARD
            },
            maskedIdentifier = secureDataManager.maskCardNumber(cardNumber),
            isDefault = setAsDefault,
            encryptedToken = tokenData,
            expiryMonth = expiryMonth,
            expiryYear = expiryYear,
            lastFourDigits = cleaned.takeLast(4)
        )

        return walletManager.addPaymentMethod(paymentMethod)
    }

    suspend fun removePaymentMethod(paymentMethodId: String): Boolean {
        return walletManager.removePaymentMethod(paymentMethodId)
    }

