    ): List<Transaction> {
        return walletManager.getTransactionHistory(limit = limit, type = type)
    }

    fun validateCard(cardNumber: String): CardValidationResult {
        return validator.validateCardNumber(cardNumber)
    }

    fun validatePaymentAmount(amount: BigDecimal): Pair<Boolean, String?> {
        return validator.validateAmount(amount)
    }

    // === Server Communication ===

    private suspend fun verifyPurchaseWithServer(purchase: Purchase): Boolean {
        return try {
            val requestBody = gson.toJson(
                mapOf(
                    "purchaseToken" to purchase.purchaseToken,
                    "productIds" to purchase.products,
                    "orderId" to purchase.orderId,
                    "packageName" to purchase.packageName
                )
            )

            val response = networkClient.post("/api/v1/verify-purchase", requestBody)

            if (response.isSuccessful) {
                log("Purchase verified with server")
                true
            } else {
                log("Server verification failed: ${response.code}")
                // In production, you might want to retry or handle specific error codes
                false
            }
        } catch